// enginebundle.js - Aim Assist (minified from engine.js)\nclass SensitivityEngine{constructor(canvas){this.canvas=canvas;this.ctx=canvas.getContext('2d');this.width=canvas.width=window.innerWidth;this.height=canvas.height=window.innerHeight;this.sensBezier=[0.25,0.1,0.25,1];this.sensLinear=0.8;this.noiseFilterSize=5;this.aimStrength=0.4;this.aimSpeed=0.12;this.fovRadius=150;this.numTargets=4;this.touchHistory=[];this.lastPos={x:0,y:0};this.vel={x:0,y:0};this.crosshair={x:this.width/2,y:this.height/2};this.targets=[];for(let i=0;i<this.numTargets;i++){this.targets.push({x:Math.random()*this.width,y:Math.random()*this.height,r:25+Math.random()*15,vx:(Math.random()-0.5)*2,vy:(Math.random()-0.5)*2,hit:false})}this.recoilControl=false;this.sensAdjust=true;this.aimStability=true;this.initTouch();this.loop()}bezier(t,p0,p1,p2,p3){const u=1-t;return u*u*u*p0+3*u*u*t*p1+3*u*t*t*p2+t*t*t*p3}applySensitivity(delta){if(!this.sensAdjust)return delta*this.sensLinear;const normDelta=Math.min(Math.abs(delta)/100,1);const curved=this.bezier(normDelta,0,this.sensBezier[0],this.sensBezier[1],1)*Math.sign(delta);return curved*100}filterTouch(pos){this.touchHistory.push(pos);if(this.touchHistory.length>this.noiseFilterSize)this.touchHistory.shift();const avg=this.touchHistory.reduce((a,b)=>({x:a.x+b.x,y:a.y+b.y}),{x:0,y:0});avg.x/=this.touchHistory.length;avg.y/=this.touchHistory.length;return avg}getClosestTarget(){let closest=null;let minDist=this.fovRadius;const cx=this.crosshair.x;const cy=this.crosshair.y;for(let target of this.targets){const dx=target.x-cx;const dy=target.y-cy;const dist=Math.sqrt(dx*dx+dy*dy);if(dist<minDist){minDist=dist;closest={target,dist,dx,dy}}}return closest}computeAimAssist(){if(!this.aimStability)return{x:0,y:0};const closest=this.getClosestTarget();if(!closest)return{x:0,y:0};const distNorm=closest.dist/this.fovRadius;const force=this.aimStrength*(1-distNorm);const dirX=closest.dx/closest.dist;const dirY=closest.dy/closest.dist;return{x:dirX*force*this.aimSpeed,y:dirY*force*this.aimSpeed}}initTouch(){this.canvas.addEventListener('touchstart',e=>{e.preventDefault();this.updateTouch(e.touches[0])},{passive:false});this.canvas.addEventListener('touchmove',e=>{e.preventDefault();this.updateTouch(e.touches[0])},{passive:false});this.canvas.addEventListener('pointermove',e=>this.updateTouch({clientX:e.clientX,clientY:e.clientY}))}updateTouch(touch){const rect=this.canvas.getBoundingClientRect();const rawPos={x:touch.clientX-rect.left,y:touch.clientY-rect.top};const filtered=this.filterTouch(rawPos);const dx=filtered.x-this.lastPos.x;const dy=filtered.y-this.lastPos.y;this.lastPos=filtered;this.vel={x:dx,y:dy};const userDx=this.applySensitivity(dx);const userDy=this.applySensitivity(dy);const aimDx=this.computeAimAssist().x;const aimDy=this.computeAimAssist().y;this.crosshair.x+=userDx+aimDx;this.crosshair.y+=userDy+aimDy;this.crosshair.x=Math.max(0,Math.min(this.width,this.crosshair.x));this.crosshair.y=Math.max(0,Math.min(this.height,this.crosshair.y))}loop(){requestAnimationFrame(()=>this.loop());this.targets.forEach(target=>{target.x+=target.vx;target.y+=target.vy;if(target.x<target.r||target.x>this.width-target.r)target.vx*=-1;if(target.y<target.r||target.y>this.height-target.r)target.vy*=-1;const dx=target.x-this.crosshair.x;const dy=target.y-this.crosshair.y;if(Math.sqrt(dx*dx+dy*dy)<target.r){target.x=Math.random()*this.width;target.y=Math.random()*this.height;target.vx=(Math.random()-0.5)*2;target.vy=(Math.random()-0.5)*2}});this.ctx.fillStyle='rgba(13,13,21,0.95)';this.ctx.fillRect(0,0,this.width,this.height);const closest=this.getClosestTarget();this.targets.forEach(target=>{const dx=target.x-this.crosshair.x;const dy=target.y-this.crosshair.y;const dist=Math.sqrt(dx*dx+dy*dy);let color='#ff4444';if(dist<this.fovRadius*.5)color='#ffaa00';if(dist<target.r)color='#00ff88';this.ctx.fillStyle=color;this.ctx.beginPath();this.ctx.arc(target.x,target.y,target.r,0,Math.PI*2);this.ctx.fill();if(target===closest?.target){this.ctx.strokeStyle='#00ff88';this.ctx.lineWidth=2;this.ctx.beginPath();this.ctx.moveTo(this.crosshair.x,this.crosshair.y);this.ctx.lineTo(target.x,target.y);this.ctx.stroke()}});this.ctx.strokeStyle='#ffffff';this.ctx.lineWidth=3;this.ctx.lineCap='round';this.ctx.beginPath();this.ctx.moveTo(this.crosshair.x-25,this.crosshair.y);this.ctx.lineTo(this.crosshair.x+25,this.crosshair.y);this.ctx.moveTo(this.crosshair.x,this.crosshair.y-25);this.ctx.lineTo(this.crosshair.x,this.crosshair.y+25);this.ctx.stroke();this.ctx.fillStyle='#ffffff';this.ctx.font='bold 16px Segoe UI';this.ctx.textAlign='left';const closestDist=closest?closest.dist.toFixed(0):'-';const aimStatus=this.aimStability?'ON':'OFF';this.ctx.fillText(`AimAssist: ${aimStatus} | Closest: ${closestDist}px | Vel: ${Math.sqrt(this.vel.x**2+this.vel.y**2).toFixed(1)} px/f`,10,30);this.ctx.textAlign='center'}toggleRecoil(on){this.recoilControl=on}toggleSens(on){this.sensAdjust=on}toggleAim(on){this.aimStability=on}}let engine;window.addEventListener('load',()=>{const canvas=document.createElement('canvas');canvas.style.position='fixed';canvas.style.top='0';canvas.style.left='0';canvas.style.zIndex='9999';document.body.appendChild(canvas);engine=new SensitivityEngine(canvas);window.engine=engine;if('serviceWorker'in navigator){navigator.serviceWorker.register('/sw.js').then(()=>console.log('SW registered'))}});
